# Drizzle Queries

Drizzle has two query APIs: a SQL-like builder that maps directly to SQL, and a relational API for nested data loading.

## SQL-Like Query Builder

### Select

```typescript
import { eq, and, or, gt, lt, like, ilike, inArray, isNull, desc, asc, sql, count, sum, avg } from 'drizzle-orm';
import { users, posts } from './schema';

// Select all
const allUsers = await db.select().from(users);

// Select specific columns
const names = await db.select({ id: users.id, name: users.name }).from(users);

// Where clause
const admins = await db.select().from(users).where(eq(users.role, 'admin'));

// Multiple conditions
const results = await db.select().from(users).where(
  and(
    eq(users.role, 'admin'),
    gt(users.createdAt, new Date('2024-01-01'))
  )
);

// OR conditions
const mixed = await db.select().from(users).where(
  or(eq(users.role, 'admin'), eq(users.role, 'moderator'))
);

// LIKE / ILIKE
const search = await db.select().from(users).where(ilike(users.name, '%dan%'));

// IN array
const specific = await db.select().from(users).where(inArray(users.id, [1, 2, 3]));

// NULL check
const noBio = await db.select().from(users).where(isNull(users.bio));

// Order, limit, offset
const paginated = await db.select().from(users)
  .orderBy(desc(users.createdAt))
  .limit(10)
  .offset(20);

// Distinct
const uniqueRoles = await db.selectDistinct({ role: users.role }).from(users);
```

### Insert

```typescript
// Single insert
await db.insert(users).values({ name: 'Dan', email: 'dan@example.com' });

// Batch insert
await db.insert(users).values([
  { name: 'Dan', email: 'dan@example.com' },
  { name: 'Alice', email: 'alice@example.com' },
]);

// Insert with returning (PostgreSQL/SQLite)
const [newUser] = await db.insert(users)
  .values({ name: 'Dan', email: 'dan@example.com' })
  .returning();

// Return specific columns
const [{ id }] = await db.insert(users)
  .values({ name: 'Dan', email: 'dan@example.com' })
  .returning({ id: users.id });

// Upsert — on conflict do update
await db.insert(users)
  .values({ id: 1, name: 'Dan', email: 'dan@example.com' })
  .onConflictDoUpdate({
    target: users.email,
    set: { name: 'Dan Updated' },
  });

// On conflict do nothing
await db.insert(users)
  .values({ email: 'dan@example.com', name: 'Dan' })
  .onConflictDoNothing({ target: users.email });

// MySQL: on duplicate key update
await db.insert(users)
  .values({ id: 1, name: 'Dan' })
  .onDuplicateKeyUpdate({ set: { name: 'Dan' } });
```

### Update

```typescript
// Basic update
await db.update(users)
  .set({ name: 'Mr. Dan' })
  .where(eq(users.id, 1));

// Update with SQL expression
await db.update(users)
  .set({ updatedAt: sql`NOW()` })
  .where(eq(users.id, 1));

// Update with returning (PostgreSQL/SQLite)
const [updated] = await db.update(users)
  .set({ name: 'Mr. Dan' })
  .where(eq(users.id, 1))
  .returning();

// Update from another table (PostgreSQL)
await db.update(users)
  .set({ cityId: cities.id })
  .from(cities)
  .where(and(eq(cities.name, 'Seattle'), eq(users.name, 'Dan')));
```

### Delete

```typescript
// Delete with condition
await db.delete(users).where(eq(users.id, 1));

// Delete with returning (PostgreSQL/SQLite)
const [deleted] = await db.delete(users)
  .where(eq(users.id, 1))
  .returning();

// Delete all rows (careful!)
await db.delete(users);
```

## Joins

```typescript
// Inner join
const result = await db.select({
  userId: users.id,
  userName: users.name,
  postTitle: posts.title,
}).from(users)
  .innerJoin(posts, eq(users.id, posts.authorId));

// Left join
const result = await db.select().from(users)
  .leftJoin(posts, eq(users.id, posts.authorId));

// Multiple joins
const result = await db.select().from(users)
  .leftJoin(posts, eq(users.id, posts.authorId))
  .leftJoin(comments, eq(posts.id, comments.postId));
```

## Aggregations

```typescript
import { count, sum, avg, min, max } from 'drizzle-orm';

// Count
const [{ total }] = await db.select({ total: count() }).from(users);

// Count with $count helper
const total = await db.$count(users);
const activeCount = await db.$count(users, eq(users.active, true));

// Group by with having
const stats = await db.select({
  role: users.role,
  userCount: count(),
}).from(users)
  .groupBy(users.role)
  .having(({ userCount }) => gt(userCount, 5));

// Sum, avg, min, max
const [{ totalViews }] = await db.select({ totalViews: sum(posts.views) }).from(posts);
```

## Subqueries and CTEs

```typescript
// Subquery
const sq = db.select({ authorId: posts.authorId, postCount: count().as('count') })
  .from(posts)
  .groupBy(posts.authorId)
  .as('post_counts');

const usersWithCounts = await db.select({
  name: users.name,
  postCount: sq.postCount,
}).from(users)
  .leftJoin(sq, eq(users.id, sq.authorId));

// CTE (WITH clause)
const activePosts = db.$with('active_posts').as(
  db.select().from(posts).where(eq(posts.published, true))
);

const result = await db.with(activePosts)
  .select().from(activePosts);
```

## Relational Query API

Requires [[drizzle/relations]] to be defined and schema passed to `drizzle()`.

```typescript
import { drizzle } from 'drizzle-orm/postgres-js';
import * as schema from './schema';

const db = drizzle(client, { schema });

// Find many with relations
const usersWithPosts = await db.query.users.findMany({
  with: {
    posts: true,
  },
});
// Returns: [{ id, name, email, posts: [{ id, title, ... }] }]

// Find first
const user = await db.query.users.findFirst({
  where: eq(users.id, 1),
  with: {
    posts: {
      where: eq(posts.published, true),
      limit: 5,
      orderBy: desc(posts.createdAt),
      with: {
        comments: true,
      },
    },
  },
});

// Select specific columns
const result = await db.query.users.findMany({
  columns: {
    id: true,
    name: true,
  },
  with: {
    posts: {
      columns: {
        title: true,
      },
    },
  },
});
```

## Raw SQL

```typescript
import { sql } from 'drizzle-orm';

// In where clauses
await db.select().from(users).where(sql`${users.name} ILIKE ${'%dan%'}`);

// Computed columns
const result = await db.select({
  name: users.name,
  nameLength: sql<number>`length(${users.name})`,
}).from(users);

// Full raw query
const rows = await db.execute(sql`SELECT * FROM users WHERE id = ${userId}`);
```

## Prepared Statements

```typescript
import { placeholder } from 'drizzle-orm';

const prepared = db.select().from(users)
  .where(eq(users.id, placeholder('id')))
  .prepare('get_user');

// Execute with parameters
const user = await prepared.execute({ id: 1 });
```

## Transactions

```typescript
await db.transaction(async (tx) => {
  const [user] = await tx.insert(users)
    .values({ name: 'Dan', email: 'dan@example.com' })
    .returning();

  await tx.insert(posts)
    .values({ title: 'First post', authorId: user.id });
});

// Nested transactions (savepoints)
await db.transaction(async (tx) => {
  await tx.insert(users).values({ name: 'Outer' });
  await tx.transaction(async (tx2) => {
    await tx2.insert(users).values({ name: 'Inner' });
  });
});
```

## Type Inference

```typescript
// Infer result types
type User = typeof users.$inferSelect;
type NewUser = typeof users.$inferInsert;

// Use in functions
const createUser = async (data: NewUser): Promise<User> => {
  const [user] = await db.insert(users).values(data).returning();
  return user;
};
```

## Filter Operators Reference

| Operator | SQL | Example |
|----------|-----|---------|
| `eq` | `=` | `eq(users.id, 1)` |
| `ne` | `<>` | `ne(users.role, 'admin')` |
| `gt` | `>` | `gt(users.age, 18)` |
| `gte` | `>=` | `gte(users.age, 18)` |
| `lt` | `<` | `lt(users.age, 65)` |
| `lte` | `<=` | `lte(users.age, 65)` |
| `like` | `LIKE` | `like(users.name, '%dan%')` |
| `ilike` | `ILIKE` | `ilike(users.name, '%dan%')` |
| `inArray` | `IN` | `inArray(users.id, [1, 2, 3])` |
| `notInArray` | `NOT IN` | `notInArray(users.id, [1, 2])` |
| `isNull` | `IS NULL` | `isNull(users.bio)` |
| `isNotNull` | `IS NOT NULL` | `isNotNull(users.bio)` |
| `between` | `BETWEEN` | `between(users.age, 18, 65)` |
| `and` | `AND` | `and(cond1, cond2)` |
| `or` | `OR` | `or(cond1, cond2)` |
| `not` | `NOT` | `not(eq(users.role, 'admin'))` |
| `sql` | raw | `sql\`custom expression\`` |
